function formatDate(dateValue) {
  if (!dateValue) return "";

  const date = new Date(dateValue);
  if (isNaN(date)) return dateValue;

  return date.toISOString().split("T")[0];
}

function formatLocalISODate(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");

  return `${year}-${month}-${day}`;
}

function showToast(message) {
  let toast = document.getElementById("toast");

  if (!toast) {
    toast = document.createElement("div");
    toast.id = "toast";
    document.body.appendChild(toast);
  }

  toast.textContent = message;
  toast.classList.add("show");

  setTimeout(() => {
    toast.classList.remove("show");
  }, 2500);
}

function openModal(modal) {
  if (!modal) return;

  modal.classList.remove("hidden");

  requestAnimationFrame(() => {
    modal.scrollTop = 0;
    const card = modal.querySelector(".modal-card");
    if (card) card.scrollTop = 0;
  });
}

function closeModal(modal) {
  if (!modal) return;
  modal.classList.add("hidden");
}

function applyFeeVisibility() {
  const isViewOnly = appMode === "view";

  if (viewerFeeAccessToggle) {
    viewerFeeAccessToggle.checked = viewerCanSeeFees;
  }

  if (isViewOnly) {
    feesVisible = viewerCanSeeFees;
    document.body.classList.toggle("hide-fees", !viewerCanSeeFees);

    if (feeToggle) {
      feeToggle.textContent = viewerCanSeeFees ? "Fees Allowed" : "Fees Hidden";
    }

    if (modeDescription) {
      modeDescription.textContent = viewerCanSeeFees
        ? "Records are viewable. Fee details are allowed by Admin."
        : "Records are viewable. Editing tools and fee details are hidden.";
    }

    return;
  }

  document.body.classList.toggle("hide-fees", !feesVisible);

  if (feeToggle) {
    feeToggle.textContent = feesVisible ? "Hide Fees" : "Show Fees";
  }
}


function getTermInfo(termValue = selectedTerm) {
  const terms = {
    all: {
      label: "All Terms",
      range: "All recorded violations"
    },
    term1: {
      label: "1st Term",
      range: "June 1 – September 9"
    },
    term2: {
      label: "2nd Term",
      range: "September 10 – December 15"
    },
    term3: {
      label: "3rd Term",
      range: "January 4 – April 3"
    }
  };

  return terms[termValue] || terms.all;
}

function getTermLabel(termValue = selectedTerm) {
  const term = getTermInfo(termValue);
  return termValue === "all" ? term.label : `${term.label}: ${term.range}`;
}

function renderTermLabel() {
  if (currentTermLabel) {
    currentTermLabel.textContent = getTermLabel();
  }
}

function getMonthDayKey(dateValue) {
  if (!dateValue) return null;

  const textDate = String(dateValue).trim();
  const match = textDate.match(/^(\d{4})-(\d{2})-(\d{2})/);

  if (match) {
    return Number(match[2]) * 100 + Number(match[3]);
  }

  const date = new Date(dateValue);
  if (isNaN(date)) return null;

  return (date.getMonth() + 1) * 100 + date.getDate();
}

function isViolationInTerm(violation, termValue = selectedTerm) {
  if (termValue === "all") return true;

  const key = getMonthDayKey(violation.date);
  if (!key) return false;

  if (termValue === "term1") return key >= 601 && key <= 909;
  if (termValue === "term2") return key >= 910 && key <= 1215;
  if (termValue === "term3") return key >= 104 && key <= 403;

  return true;
}

function getVisibleViolations(student) {
  if (!student || !Array.isArray(student.violations)) return [];
  return student.violations.filter(violation =>
    isViolationInTerm(violation, selectedTerm)
  );
}

function normalizeStatusText(value) {
  return String(value || "").trim().toLowerCase().replace(/\s+/g, " ");
}

function isPaidWithKindnessStatus(value) {
  const status = normalizeStatusText(value);
  return status === "paid with kindness" ||
    status === "paid thru kindness" ||
    status === "paid through kindness" ||
    (status.includes("paid") && status.includes("kindness"));
}

function isPaidStatus(value) {
  return normalizeStatusText(value) === "paid";
}

function isUnpaidStatus(value) {
  return normalizeStatusText(value) === "unpaid";
}

function isWaivedStatus(value) {
  return normalizeStatusText(value) === "waived";
}

function getStatusFilterKey(value) {
  if (isPaidWithKindnessStatus(value)) return "paidwithkindness";
  if (isPaidStatus(value)) return "paid";
  if (isUnpaidStatus(value)) return "unpaid";
  if (isWaivedStatus(value)) return "waived";
  return normalizeStatusText(value).replace(/[^a-z0-9]+/g, "");
}

function getStatusClass(value) {
  return getStatusFilterKey(value) || "unknown";
}

function isKindnessSettlementType(value) {
  return String(value || "").trim().toLowerCase().includes("kindness");
}

function isCashFeeRecord(violation) {
  return !isKindnessSettlementType(violation && violation.settlementType) &&
    !isPaidWithKindnessStatus(violation && violation.status);
}

function getMonetaryFee(violation) {
  return isCashFeeRecord(violation) ? (Number(violation && violation.fee) || 0) : 0;
}

function getFeeDisplay(violation) {
  if (!violation) return "₱0";
  if (isKindnessRecord(violation)) return "Kindness Alternative";
  return `₱${Number(violation.fee) || 0}`;
}

function getPaidWithKindnessCount(violations) {
  return (violations || []).filter(v => isPaidWithKindnessStatus(v.status) || isKindnessCompleted(v)).length;
}

function getSuggestedKindnessTaskForViolationName(violationName) {
  const selectedType = violationFees.find(item => item.name === violationName);
  if (!selectedType || !selectedType.kindnessAlternative) return "";

  return `${selectedType.kindnessAlternative}${selectedType.kindnessValue ? ` (${selectedType.kindnessValue})` : ""}`;
}

function getEffectiveKindnessTask(violation) {
  if (!violation) return "";
  return violation.kindnessTask || getSuggestedKindnessTaskForViolationName(violation.type) || "";
}

function getEffectiveKindnessStatus(violation) {
  if (!violation) return "";
  if (isPaidWithKindnessStatus(violation.status)) return "Completed";
  if (isResolvedStatus(violation.kindnessStatus)) return "Completed";
  if (violation.kindnessCompletedDate) return "Completed";
  return violation.kindnessStatus || "Pending";
}

function getEffectiveKindnessCompletedDate(violation) {
  if (!violation) return "";
  return formatDate(violation.kindnessCompletedDate || "");
}

function isKindnessCompleted(violation) {
  return isResolvedStatus(getEffectiveKindnessStatus(violation));
}

function normalizeLoadedKindnessRecord(violation) {
  if (!violation) return violation;

  if (isPaidWithKindnessStatus(violation.status)) {
    violation.settlementType = violation.settlementType && isKindnessSettlementType(violation.settlementType)
      ? violation.settlementType
      : "Kindness Alternative";
    violation.kindnessStatus = "Completed";
  }

  if (isKindnessRecord(violation)) {
    if (!violation.kindnessTask) {
      violation.kindnessTask = getSuggestedKindnessTaskForViolationName(violation.type) || "";
    }
    if (violation.kindnessCompletedDate && !isResolvedStatus(violation.kindnessStatus)) {
      violation.kindnessStatus = "Completed";
    }
  }

  return violation;
}

function syncKindnessTaskForForm(settlementElement, violationElement, taskElement) {
  if (!settlementElement || !violationElement || !taskElement) return;

  if (!isKindnessSettlementType(settlementElement.value)) return;

  const suggestedTask = getSuggestedKindnessTaskForViolationName(violationElement.value);
  if (!suggestedTask) return;

  if (!taskElement.value.trim() || taskElement.dataset.autoSuggested === "true") {
    taskElement.value = suggestedTask;
    taskElement.dataset.autoSuggested = "true";
  }
}

function markKindnessTaskAsCustom(taskElement) {
  if (!taskElement) return;
  taskElement.dataset.autoSuggested = "false";
}

function syncKindnessCompletedDateForStatus(kindnessStatusElement, completedDateElement) {
  if (!kindnessStatusElement || !completedDateElement) return;

  if (isResolvedStatus(kindnessStatusElement.value) && !completedDateElement.value) {
    completedDateElement.value = getTodayISO();
  }
}

function applyPaidWithKindnessStatus(statusElement, settlementElement, violationElement, taskElement, kindnessStatusElement, completedDateElement, advancedElement) {
  if (!statusElement || !isPaidWithKindnessStatus(statusElement.value)) return;

  if (settlementElement) {
    settlementElement.value = "Kindness Alternative";
  }

  if (advancedElement) {
    advancedElement.open = true;
  }

  if (taskElement) {
    taskElement.dataset.autoSuggested = "true";
  }

  syncKindnessTaskForForm(settlementElement, violationElement, taskElement);

  if (kindnessStatusElement) {
    kindnessStatusElement.value = "Completed";
  }

  if (completedDateElement && !completedDateElement.value) {
    completedDateElement.value = getTodayISO();
  }
}

function getKindnessSettlementRecords() {
  const items = [];

  students.forEach(student => {
    getVisibleViolations(student).forEach(violation => {
      if (!isKindnessRecord(violation)) return;
      items.push({ student, violation });
    });
  });

  return items.sort((a, b) =>
    String(a.violation.kindnessStatus || "Pending").localeCompare(String(b.violation.kindnessStatus || "Pending")) ||
    a.student.name.localeCompare(b.student.name) ||
    new Date(b.violation.date) - new Date(a.violation.date)
  );
}

function getRepeatedViolation(student) {
  const count = {};
  const violations = getVisibleViolations(student);

  violations.forEach(v => {
    count[v.type] = (count[v.type] || 0) + 1;
  });

  return Object.entries(count).find(([_, total]) => total >= 3);
}

function getLatestViolationDate(student) {
  const violations = getVisibleViolations(student);

  if (violations.length === 0) return 0;
  return Math.max(...violations.map(v => new Date(v.date).getTime()));
}

function hasBehaviorAlertTrigger(student) {
  const violations = getVisibleViolations(student);
  return violations.length >= 5 || Boolean(getRepeatedViolation(student));
}

function isParentContactHandled(violation) {
  return String(violation && violation.parentContacted || "").trim().toLowerCase() === "yes";
}

function isFollowUpHandledForAlert(violation) {
  return isResolvedStatus(violation && violation.followUpStatus);
}

function isSettlementHandledForAlert(violation) {
  const status = normalizeStatusText(violation && violation.status);

  if (isPaidWithKindnessStatus(status)) return true;
  if (["paid", "waived", "settled", "completed", "done", "no fee"].includes(status)) return true;

  if (isKindnessRecord(violation)) {
    return isKindnessCompleted(violation);
  }

  return getMonetaryFee(violation) <= 0 && status !== "unpaid";
}

function isAlertRecordHandled(violation) {
  return isParentContactHandled(violation) &&
    isFollowUpHandledForAlert(violation) &&
    isSettlementHandledForAlert(violation);
}

function getAlertReviewRecords(student) {
  const violations = getVisibleViolations(student);
  const repeated = getRepeatedViolation(student);

  if (violations.length >= 5) return violations;
  if (repeated) return violations.filter(v => v.type === repeated[0]);

  return [];
}

function getActiveAlertDetails(student) {
  const violations = getVisibleViolations(student);
  const repeated = getRepeatedViolation(student);
  const reviewRecords = getAlertReviewRecords(student);

  if (!reviewRecords.length) {
    return {
      active: false,
      hasTrigger: false,
      reason: "No active alert.",
      missing: [],
      handledCount: 0,
      totalReview: 0
    };
  }

  const missing = [];
  if (reviewRecords.some(v => !isParentContactHandled(v))) missing.push("Parent Contact");
  if (reviewRecords.some(v => !isFollowUpHandledForAlert(v))) missing.push("Follow-up Improved/Resolved");
  if (reviewRecords.some(v => !isSettlementHandledForAlert(v))) missing.push("Settlement");

  const handledCount = reviewRecords.filter(isAlertRecordHandled).length;
  let reason = `Total Violations: ${violations.length}`;
  if (repeated) reason = `Repeated: ${repeated[0]} (${repeated[1]}x)`;
  if (violations.length >= 5) reason = `Total Alert: ${violations.length} violations`;

  return {
    active: missing.length > 0,
    hasTrigger: true,
    reason,
    missing,
    handledCount,
    totalReview: reviewRecords.length,
    repeated
  };
}

function hasAlert(student) {
  return getActiveAlertDetails(student).active;
}

function getStudentStatus(student) {
  const total = getVisibleViolations(student).length;
  const repeated = getRepeatedViolation(student);
  const alertDetails = getActiveAlertDetails(student);

  if (alertDetails.active && total >= 5) return { label: "Needs Support", className: "support", icon: "🔴" };
  if (alertDetails.active && (total >= 3 || repeated)) return { label: "Needs Guidance", className: "guidance", icon: "🟡" };
  if (alertDetails.hasTrigger) return { label: "Resolved / Monitored", className: "track", icon: "🟢" };

  return { label: "On Track", className: "track", icon: "🟢" };
}

function getGenderRank(student) {
  const gender = String(student.gender || "").trim().toLowerCase();

  if (["boy", "boys", "male", "m", "b", "lalaki", "men", "man"].includes(gender)) return 0;
  if (["girl", "girls", "female", "f", "g", "babae", "women", "woman"].includes(gender)) return 1;

  return 2;
}

function sortByName(a, b) {
  return a.lastName.localeCompare(b.lastName) ||
    a.firstName.localeCompare(b.firstName) ||
    a.name.localeCompare(b.name);
}

function sortByGenderThenName(a, b) {
  return getGenderRank(a) - getGenderRank(b) || sortByName(a, b);
}

function getSortedStudents() {
  const sortValue = studentSort.value;
  const searchValue = studentSearch.value.toLowerCase().trim();

  let sorted = [...students];

  if (searchValue) {
    sorted = sorted.filter(student =>
      student.name.toLowerCase().includes(searchValue)
    );
  }

  if (sortValue === "az") {
    sorted.sort(sortByName);
  }

  if (sortValue === "boysGirls") {
    sorted.sort(sortByGenderThenName);
  }

  if (sortValue === "most") {
    sorted.sort((a, b) =>
      (getVisibleViolations(b).length - getVisibleViolations(a).length) ||
      a.lastName.localeCompare(b.lastName) ||
      a.firstName.localeCompare(b.firstName)
    );
  }

  if (sortValue === "newest") {
    sorted.sort((a, b) =>
      (getLatestViolationDate(b) - getLatestViolationDate(a)) ||
      a.lastName.localeCompare(b.lastName) ||
      a.firstName.localeCompare(b.firstName)
    );
  }

  if (sortValue === "alerts") {
    sorted = sorted
      .filter(student => hasAlert(student))
      .sort((a, b) =>
        a.lastName.localeCompare(b.lastName) ||
        a.firstName.localeCompare(b.firstName)
      );
  }

  return sorted;
}

function getTodayISO() {
  const today = new Date();
  today.setMinutes(today.getMinutes() - today.getTimezoneOffset());
  return today.toISOString().split("T")[0];
}

function getCurrentMonthISO() {
  return getTodayISO().slice(0, 7);
}

function formatDisplayDate(dateValue) {
  if (!dateValue) return "";

  const date = new Date(`${dateValue}T00:00:00`);
  if (isNaN(date)) return dateValue;

  return date.toLocaleDateString("en-US", {
    month: "long",
    day: "numeric",
    year: "numeric"
  });
}

function escapeHTML(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function normalizeKey(key) {
  return String(key || "").toLowerCase().replace(/[^a-z0-9]/g, "");
}

function normalizeKeys(obj) {
  const normalized = {};

  Object.keys(obj || {}).forEach(key => {
    normalized[normalizeKey(key)] = obj[key];
  });

  return normalized;
}

function ensureAttendanceDefaults() {
  if (attendanceDate && !attendanceDate.value) {
    attendanceDate.value = getTodayISO();
  }

  if (attendanceMonth && !attendanceMonth.value) {
    attendanceMonth.value = getCurrentMonthISO();
  }
}

function rebuildAttendanceIndex() {
  attendanceByDate = {};

  attendanceRecords.forEach(record => {
    if (!record.date || !record.studentId) return;

    if (!attendanceByDate[record.date]) {
      attendanceByDate[record.date] = {};
    }

    attendanceByDate[record.date][record.studentId] = {
      status: normalizeAttendanceStatusValue(record.status),
      remarks: record.remarks || "",
      attendanceId: record.attendanceId || ""
    };
  });
}

function getAttendanceDateValue() {
  ensureAttendanceDefaults();
  return attendanceDate ? attendanceDate.value : getTodayISO();
}

function getAttendanceEntry(studentId, dateValue = getAttendanceDateValue()) {
  const dateRecords = attendanceByDate[dateValue] || {};

  return dateRecords[studentId] || {
    status: "Present",
    remarks: "",
    attendanceId: ""
  };
}

function setLocalAttendance(studentId, updates) {
  const dateValue = getAttendanceDateValue();

  if (!attendanceByDate[dateValue]) {
    attendanceByDate[dateValue] = {};
  }

  const current = getAttendanceEntry(studentId, dateValue);

  attendanceByDate[dateValue][studentId] = {
    ...current,
    ...updates
  };
}

function getAttendanceRowsForDate(dateValue = getAttendanceDateValue()) {
  return students.map(student => {
    const entry = getAttendanceEntry(student.id, dateValue);

    return {
      student,
      status: normalizeAttendanceStatusValue(entry.status),
      remarks: entry.remarks || "",
      attendanceId: entry.attendanceId || ""
    };
  });
}

function normalizeAttendanceRemarksValue(value) {
  return String(value || "").trim();
}

function buildSparseAttendanceSnapshot(dateValue = getAttendanceDateValue()) {
  const snapshot = {};

  students.forEach(student => {
    const entry = getAttendanceEntry(student.id, dateValue);
    const status = normalizeAttendanceStatusValue(entry.status);
    const remarks = normalizeAttendanceRemarksValue(entry.remarks);

    if (status !== "Present" || remarks) {
      snapshot[student.id] = { status, remarks };
    }
  });

  return snapshot;
}

function ensureAttendanceSavedSnapshot(dateValue = getAttendanceDateValue()) {
  if (!attendanceSavedSnapshotByDate[dateValue]) {
    attendanceSavedSnapshotByDate[dateValue] = buildSparseAttendanceSnapshot(dateValue);
  }

  return attendanceSavedSnapshotByDate[dateValue];
}

function attendanceSnapshotEntry(snapshot, studentId) {
  return snapshot[studentId] || { status: "Present", remarks: "" };
}

function getChangedAttendanceRecords(dateValue = getAttendanceDateValue()) {
  const original = ensureAttendanceSavedSnapshot(dateValue);
  const current = buildSparseAttendanceSnapshot(dateValue);
  const changedIds = new Set([
    ...Object.keys(original),
    ...Object.keys(current)
  ]);

  return [...changedIds].map(studentId => {
    const before = attendanceSnapshotEntry(original, studentId);
    const after = attendanceSnapshotEntry(current, studentId);

    if (before.status === after.status && before.remarks === after.remarks) {
      return null;
    }

    return {
      studentId,
      status: after.status,
      remarks: after.remarks
    };
  }).filter(Boolean);
}

function getAttendanceCounts(rows) {
  const counts = {
    Present: 0,
    Absent: 0,
    Excused: 0,
    Tardy: 0
  };

  rows.forEach(row => {
    counts[row.status] = (counts[row.status] || 0) + 1;
  });

  counts.Present += counts.Tardy;

  return counts;
}

function renderAttendanceSummary(rows) {
  if (!attendanceSummary) return;

  const counts = getAttendanceCounts(rows);

  attendanceSummary.innerHTML = `
    <button type="button" class="attendance-count-chip present" data-attendance-status="Present"><span>Present</span><strong>${counts.Present}</strong></button>
    <button type="button" class="attendance-count-chip absent" data-attendance-status="Absent"><span>Absent</span><strong>${counts.Absent}</strong></button>
    <button type="button" class="attendance-count-chip excused" data-attendance-status="Excused"><span>Excused</span><strong>${counts.Excused}</strong></button>
    <button type="button" class="attendance-count-chip tardy" data-attendance-status="Tardy"><span>Tardy</span><strong>${counts.Tardy}</strong></button>
    <button type="button" class="attendance-count-chip total" data-attendance-status="all"><span>Total</span><strong>${rows.length}</strong></button>
  `;
}

function renderAttendanceQuickSummary() {
  if (!attendanceQuickSummary) return;

  const rows = getAttendanceRowsForDate(getTodayISO());
  const counts = getAttendanceCounts(rows);
  const issueCount = counts.Absent + counts.Excused + counts.Tardy;
  const todayLabel = `Today • ${formatDisplayDate(getTodayISO())}`;
  const snapshot = issueCount
    ? `${counts.Absent} absent • ${counts.Tardy} tardy • ${counts.Excused} excused today`
    : "All students are currently marked Present";

  if (attendanceQuickDate) {
    attendanceQuickDate.textContent = todayLabel;
  }

  attendanceQuickSummary.innerHTML = `
    <p class="attendance-snapshot">${snapshot}</p>
    <button type="button" class="attendance-stat-card present" data-attendance-status="Present">
      <span>Present</span>
      <strong>${counts.Present}</strong>
    </button>
    <button type="button" class="attendance-stat-card absent" data-attendance-status="Absent">
      <span>Absent</span>
      <strong>${counts.Absent}</strong>
    </button>
    <button type="button" class="attendance-stat-card excused" data-attendance-status="Excused">
      <span>Excused</span>
      <strong>${counts.Excused}</strong>
    </button>
    <button type="button" class="attendance-stat-card tardy" data-attendance-status="Tardy">
      <span>Tardy</span>
      <strong>${counts.Tardy}</strong>
    </button>
    <button type="button" class="attendance-stat-card total" data-attendance-status="all">
      <span>Total Students</span>
      <strong>${rows.length}</strong>
    </button>
  `;
}

function renderAttendanceBoard(rows) {
  if (!attendanceBoardList) return;

  const dateValue = getAttendanceDateValue();
  const showAll = attendanceShowAll ? attendanceShowAll.checked : false;
  const groupOrder = showAll
    ? ["Absent", "Tardy", "Excused", "Present"]
    : ["Absent", "Tardy", "Excused"];

  if (attendanceBoardTitle) {
    attendanceBoardTitle.textContent =
      dateValue === getTodayISO() ? "Today's Attendance" : "Selected Date Attendance";
  }

  if (attendanceBoardDate) {
    attendanceBoardDate.textContent = formatDisplayDate(dateValue);
  }

  const groups = groupOrder.map(status => {
    const matching = rows.filter(row =>
      status === "Present"
        ? row.status === "Present" || row.status === "Tardy"
        : row.status === status
    );

    return `
      <div class="attendance-group ${status.toLowerCase()}">
        <h3>${status} <span>${matching.length}</span></h3>
        ${
          matching.length
            ? `<ul>${matching.map(row => `
                <li>
                  <strong>${escapeHTML(row.student.name)}</strong>
                  ${status === "Present" && row.status === "Tardy" ? `<span class="attendance-inline-tag tardy">Tardy</span>` : ""}
                  ${row.remarks ? `<small>${escapeHTML(row.remarks)}</small>` : ""}
                </li>
              `).join("")}</ul>`
            : `<p class="empty-message">None</p>`
        }
      </div>
    `;
  });

  attendanceBoardList.innerHTML = groups.join("");
}

function openAttendanceStatusModal(status, dateValue = getTodayISO()) {
  if (!attendanceStatusModal || !attendanceStatusList) return;

  const rows = getAttendanceRowsForDate(dateValue)
    .filter(row => {
      if (status === "all") return true;
      if (status === "Present") return row.status === "Present" || row.status === "Tardy";
      return row.status === status;
    })
    .sort((a, b) => sortByGenderThenName(a.student, b.student));

  const title = status === "all" ? "All Students" : `${status} Students`;

  if (attendanceStatusTitle) {
    attendanceStatusTitle.textContent = title;
  }

  if (attendanceStatusSubtitle) {
    attendanceStatusSubtitle.textContent = formatDisplayDate(dateValue);
  }

  attendanceStatusList.innerHTML = rows.length
    ? rows.map(row => `
        <div class="attendance-status-item status-${row.status.toLowerCase()}">
          <strong>${escapeHTML(row.student.name)}</strong>
          <span>${row.status}${row.remarks ? ` • ${escapeHTML(row.remarks)}` : ""}</span>
        </div>
      `).join("")
    : `<p class="empty-message">No students in this status.</p>`;

  openModal(attendanceStatusModal);
}

function closeAttendanceStatusPopup() {
  if (!attendanceStatusModal) return;
  attendanceStatusModal.classList.add("hidden");
}

function renderAttendanceList(rows) {
  if (!attendanceList) return;

  const searchValue = attendanceSearch ? attendanceSearch.value.toLowerCase().trim() : "";
  const filterValue = attendanceFilter ? attendanceFilter.value : "all";
  const sortValue = attendanceSort ? attendanceSort.value : "az";

  let visibleRows = [...rows];

  if (searchValue) {
    visibleRows = visibleRows.filter(row =>
      row.student.name.toLowerCase().includes(searchValue)
    );
  }

  if (filterValue !== "all") {
    visibleRows = visibleRows.filter(row => row.status === filterValue);
  }

  const statusRank = {
    Absent: 0,
    Tardy: 1,
    Excused: 2,
    Present: 3
  };

  if (sortValue === "exceptions") {
    visibleRows.sort((a, b) =>
      statusRank[a.status] - statusRank[b.status] ||
      sortByName(a.student, b.student)
    );
  } else if (sortValue === "boysGirls") {
    visibleRows.sort((a, b) => sortByGenderThenName(a.student, b.student));
  } else if (sortValue === "az") {
    visibleRows.sort((a, b) => sortByName(a.student, b.student));
  } else {
    visibleRows.sort((a, b) => {
      if (a.status === sortValue && b.status !== sortValue) return -1;
      if (a.status !== sortValue && b.status === sortValue) return 1;
      return sortByName(a.student, b.student);
    });
  }

  if (visibleRows.length === 0) {
    attendanceList.innerHTML = `<p class="empty-message">No students found for this view.</p>`;
    return;
  }

  const disabled = appMode === "admin" ? "" : "disabled";

  attendanceList.innerHTML = visibleRows.map(row => `
    <div class="attendance-row status-${row.status.toLowerCase()}" data-student-id="${escapeHTML(row.student.id)}">
      <button
        type="button"
        class="attendance-tap-target"
        data-student-id="${escapeHTML(row.student.id)}"
        onclick="markAttendanceStudent(this.dataset.studentId)"
        ${appMode === "admin" ? "" : "disabled"}
      >
        <span>
          <strong>${escapeHTML(row.student.name)}</strong>
          <small>${row.remarks ? escapeHTML(row.remarks) : "Tap to mark selected status"}</small>
        </span>
        <b>${row.status}</b>
      </button>

      <input
        class="attendance-remarks"
        type="text"
        placeholder="Remarks optional..."
        value="${escapeHTML(row.remarks)}"
        data-student-id="${escapeHTML(row.student.id)}"
        ${disabled}
      />
    </div>
  `).join("");
}

function renderAttendance() {
  if (!attendanceList) return;

  ensureAttendanceDefaults();
  renderAttendanceMarkMode();

  const rows = getAttendanceRowsForDate();

  renderAttendanceSummary(rows);
  renderAttendanceBoard(rows);
  renderAttendanceList(rows);
}

function markAttendanceStudent(studentId) {
  if (appMode !== "admin" || !studentId) return;

  ensureAttendanceSavedSnapshot(getAttendanceDateValue());

  setLocalAttendance(studentId, {
    status: attendanceMarkMode
  });

  renderAttendance();
}

window.markAttendanceStudent = markAttendanceStudent;

function renderMonthlyAttendance() {
  if (!monthlyAttendanceList) return;

  ensureAttendanceDefaults();

  const monthValue = attendanceMonth ? attendanceMonth.value : getCurrentMonthISO();

  const rows = students.map(student => {
    const counts = {
      Present: 0,
      Absent: 0,
      Excused: 0,
      Tardy: 0
    };

    attendanceRecords
      .filter(record => record.studentId === student.id && record.date.slice(0, 7) === monthValue)
      .forEach(record => {
        const status = normalizeAttendanceStatusValue(record.status);
        counts[status] += 1;
      });

    counts.Present += counts.Tardy;

    return {
      student,
      counts,
      total: counts.Present + counts.Absent + counts.Excused
    };
  });

  if (rows.length === 0) {
    monthlyAttendanceList.innerHTML = `<p class="empty-message">No students loaded yet.</p>`;
    return;
  }

  monthlyAttendanceList.innerHTML = `
    <table>
      <thead>
        <tr>
          <th>Student</th>
          <th>Present</th>
          <th>Absent</th>
          <th>Excused</th>
          <th>Tardy</th>
          <th>Total</th>
        </tr>
      </thead>
      <tbody>
        ${rows
          .sort((a, b) => sortByGenderThenName(a.student, b.student))
          .map(row => `
            <tr>
              <td>${escapeHTML(row.student.name)}</td>
              <td>${row.counts.Present}</td>
              <td>${row.counts.Absent}</td>
              <td>${row.counts.Excused}</td>
              <td>${row.counts.Tardy}</td>
              <td>${row.total}</td>
            </tr>
          `).join("")}
      </tbody>
    </table>
  `;
}

function getMonthlyAttendanceRows(monthValue = getCurrentMonthISO()) {
  return students.map(student => {
    const counts = {
      Present: 0,
      Absent: 0,
      Excused: 0,
      Tardy: 0
    };

    attendanceRecords
      .filter(record => record.studentId === student.id && record.date.slice(0, 7) === monthValue)
      .forEach(record => {
        const status = normalizeAttendanceStatusValue(record.status);
        counts[status] += 1;
      });

    counts.Present += counts.Tardy;

    return {
      student,
      counts,
      total: counts.Present + counts.Absent + counts.Excused
    };
  }).sort((a, b) => sortByGenderThenName(a.student, b.student));
}

function getMonthlyAttendanceDates(monthValue) {
  const [year, month] = String(monthValue || getCurrentMonthISO())
    .split("-")
    .map(value => Number(value));
  const firstDay = new Date(year, month - 1, 1);
  const firstDayOfWeek = firstDay.getDay();
  let mondayOffset = 0;

  if (firstDayOfWeek === 0) {
    mondayOffset = 1;
  } else if (firstDayOfWeek === 6) {
    mondayOffset = 2;
  } else {
    mondayOffset = 1 - firstDayOfWeek;
  }

  const firstSchoolMonday = new Date(year, month - 1, 1 + mondayOffset);
  const schoolDays = [];

  for (let week = 0; week < 5; week += 1) {
    for (let weekday = 0; weekday < 5; weekday += 1) {
      const date = new Date(firstSchoolMonday);
      date.setDate(firstSchoolMonday.getDate() + (week * 7) + weekday);

      schoolDays.push(date.getMonth() === month - 1 ? formatLocalISODate(date) : "");
    }
  }

  return schoolDays;
}

function chunkItems(items, size) {
  const chunks = [];

  for (let i = 0; i < items.length; i += size) {
    chunks.push(items.slice(i, i + size));
  }

  return chunks.length ? chunks : [[]];
}

function getAttendancePrintMark(studentId, dateValue) {
  const entry = getAttendanceEntry(studentId, dateValue);
  const status = normalizeAttendanceStatusValue(entry.status);

  if (status === "Absent") return "X";
  if (status === "Tardy") return "T";
  if (status === "Excused") return "E";

  return "";
}

function getOfficialAttendanceGroups(rows) {
  const boys = rows.filter(row => getGenderRank(row.student) === 0);
  const girls = rows.filter(row => getGenderRank(row.student) === 1);
  const unsorted = rows.filter(row => getGenderRank(row.student) === 2);

  if (boys.length || girls.length) {
    return [
      { label: "BOYS", rows: boys },
      { label: "GIRLS", rows: [...girls, ...unsorted] }
    ];
  }

  return [{ label: "STUDENTS", rows: unsorted }];
}

function getMonthlyAttendanceNonPresentTotal(studentId, dateValues) {
  return dateValues.reduce((total, dateValue) => {
    const entry = getAttendanceEntry(studentId, dateValue);
    return entry.status && entry.status !== "Present" ? total + 1 : total;
  }, 0);
}

function getMonthlyAttendanceStatusTotal(studentId, dateValues, status) {
  return dateValues.reduce((total, dateValue) => {
    const entry = getAttendanceEntry(studentId, dateValue);
    return entry.status === status ? total + 1 : total;
  }, 0);
}

function escapeXML(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function getColumnName(index) {
  let name = "";
  let current = index;

  while (current > 0) {
    const remainder = (current - 1) % 26;
    name = String.fromCharCode(65 + remainder) + name;
    current = Math.floor((current - 1) / 26);
  }

  return name;
}

function getCellRef(row, col) {
  return `${getColumnName(col)}${row}`;
}

function buildTextCell(row, col, value, style = 0) {
  if (value === null || value === undefined) return "";
  if (value === "") return `<c r="${getCellRef(row, col)}" s="${style}"/>`;

  return `<c r="${getCellRef(row, col)}" t="inlineStr" s="${style}"><is><t>${escapeXML(value)}</t></is></c>`;
}

function buildNumberCell(row, col, value, style = 0) {
  if (value === null || value === undefined) return "";
  if (value === "") return `<c r="${getCellRef(row, col)}" s="${style}"/>`;

  return `<c r="${getCellRef(row, col)}" s="${style}"><v>${Number(value) || 0}</v></c>`;
}

function getMonthFileLabel(monthValue) {
  return new Date(`${monthValue}-01T00:00:00`)
    .toLocaleDateString("en-US", { month: "long", year: "numeric" });
}

function buildOfficialAttendanceSheetRows(rows, dateValues, sectionLabel, monthLabel) {
  const sheetRows = [];
  const attendanceGroups = getOfficialAttendanceGroups(rows);
  const firstGroupLabel = attendanceGroups[0] ? attendanceGroups[0].label : "STUDENTS";
  const merges = [
    "A5:AC5",
    "B6:AC6",
    "B7:AC7",
    "A9:R9",
    "S9:AC9",
    "A10:B10",
    "A11:B11",
    "C10:AA10",
    "AB10:AC10"
  ];

  const addRow = (rowNumber, height, cells = "") => {
    sheetRows.push(`<row r="${rowNumber}"${height ? ` ht="${height}" customHeight="1"` : ""}>${cells}</row>`);
  };

  [1, 2, 3, 4].forEach(row => addRow(row, row <= 2 ? 12.75 : 22.5));
  addRow(5, 15, buildTextCell(5, 1, "STUDENT BEHAVIORAL MANAGEMENT OFFICE", 1));
  addRow(6, 15, buildTextCell(6, 2, "DAILY ATTENDANCE RECORD", 1));
  addRow(7, 15, buildTextCell(7, 2, "School Year 2026 - 2027", 1));
  addRow(8, 6.75);
  addRow(
    9,
    20.25,
    buildTextCell(9, 1, `Grade & Section:  ${sectionLabel}`.toUpperCase(), 2) +
      buildTextCell(9, 19, `Month:  ${monthLabel}`, 2)
  );
  addRow(
    10,
    10.5,
    buildTextCell(10, 1, "NAME OF STUDENTS", 3) +
      buildTextCell(10, 3, "D A T E S", 3) +
      buildTextCell(10, 28, "TOTAL", 3)
  );
  addRow(
    11,
    27,
    buildTextCell(11, 1, firstGroupLabel, 5) +
      dateValues.map((dateValue, index) =>
      buildNumberCell(11, index + 3, dateValue ? Number(dateValue.slice(8, 10)) : "", (index + 1) % 5 === 0 ? 20 : 10)
    ).join("") +
      buildTextCell(11, 28, "T", 10) +
      buildTextCell(11, 29, "X", 10)
  );

  let rowNumber = 12;

  attendanceGroups.forEach((group, groupIndex) => {
    const minimumRows = 25;
    const slotCount = Math.max(minimumRows, group.rows.length);
    const slots = Array.from({ length: slotCount }, (_, index) => group.rows[index] || null);

    if (groupIndex > 0) {
      merges.push(`A${rowNumber}:B${rowNumber}`);
      addRow(
        rowNumber,
        15,
        buildTextCell(rowNumber, 1, group.label, 5)
      );
      rowNumber += 1;
    }

    slots.forEach((row, index) => {
      const isBlockEnd = (index + 1) % 5 === 0;
      const numberStyle = isBlockEnd ? 10 : 6;
      const nameStyle = isBlockEnd ? 11 : 7;
      const totalStyle = isBlockEnd ? 22 : 21;
      const student = row ? row.student : null;
      const tardyTotal = student ? getMonthlyAttendanceStatusTotal(student.id, dateValues, "Tardy") : "";
      const absentTotal = student ? getMonthlyAttendanceStatusTotal(student.id, dateValues, "Absent") : "";
      const cells = [
        buildNumberCell(rowNumber, 1, index + 1, numberStyle),
        buildTextCell(rowNumber, 2, student ? student.name.toUpperCase() : "", nameStyle),
        ...dateValues.map((dateValue, dateIndex) => {
          const isWeekEnd = (dateIndex + 1) % 5 === 0;
          const markStyle = isWeekEnd
            ? (isBlockEnd ? 24 : 23)
            : (isBlockEnd ? 22 : 21);

          return buildTextCell(
            rowNumber,
            dateIndex + 3,
            student ? getAttendancePrintMark(student.id, dateValue) : "",
            markStyle
          );
        }),
        buildNumberCell(
          rowNumber,
          28,
          tardyTotal || "",
          totalStyle
        ),
        buildNumberCell(
          rowNumber,
          29,
          absentTotal || "",
          totalStyle
        )
      ].join("");

      addRow(rowNumber, 14.25, cells);
      rowNumber += 1;
    });
  });

  rowNumber += 1;
  addRow(rowNumber, 13.5, buildTextCell(rowNumber, 2, "LEGEND:", 13));
  merges.push(`L${rowNumber + 1}:Z${rowNumber + 3}`);
  addRow(
    rowNumber + 1,
    13.5,
    buildTextCell(rowNumber + 1, 2, "X - Absent", 13) +
      buildTextCell(
        rowNumber + 1,
        12,
        "Important: Submit a written report to the SBMO Heads after a student has been absent for three (3) consecutive days / five (5) accumulated days",
        14
      )
  );
  addRow(rowNumber + 2, 13.5, buildTextCell(rowNumber + 2, 2, "T - Tardiness", 13));
  addRow(rowNumber + 3, 13.5, buildTextCell(rowNumber + 3, 2, "E - Excused", 13));
  addRow(rowNumber + 4, 13.5, buildTextCell(rowNumber + 4, 2, "S - Class Suspension", 13));
  addRow(rowNumber + 5, 13.5, buildTextCell(rowNumber + 5, 2, "H - Holiday", 13));

  merges.push(`B${rowNumber + 7}:J${rowNumber + 7}`);
  merges.push(`B${rowNumber + 8}:J${rowNumber + 8}`);
  merges.push(`T${rowNumber + 7}:AC${rowNumber + 7}`);
  merges.push(`T${rowNumber + 8}:AC${rowNumber + 8}`);
  merges.push(`T${rowNumber + 9}:AC${rowNumber + 9}`);
  addRow(rowNumber + 7, 13.5, buildTextCell(rowNumber + 7, 2, "Note: Pls. Use red ballpen for your markings", 15) + buildTextCell(rowNumber + 7, 20, "Mr. John Rey E. Tubello", 16));
  addRow(rowNumber + 8, 13.5, buildTextCell(rowNumber + 8, 2, "* Submission every end of the month", 15) + buildTextCell(rowNumber + 8, 20, "____________________________", 16));
  addRow(rowNumber + 9, 13.5, buildTextCell(rowNumber + 9, 20, "Adviser's Signature over Printed Name", 17));

  return {
    rows: sheetRows.join(""),
    merges,
    lastRow: rowNumber + 9
  };
}

function buildOfficialAttendanceSheetXml({ rows, dateValues, sectionLabel, monthLabel, sheetIndex, includeImage }) {
  const printableDates = dateValues.length
    ? [...dateValues, ...Array(Math.max(0, 25 - dateValues.length)).fill("")]
    : Array.from({ length: 25 }, () => "");
  const sheet = buildOfficialAttendanceSheetRows(rows, printableDates, sectionLabel, monthLabel);
  const mergeXml = sheet.merges.length
    ? `<mergeCells count="${sheet.merges.length}">${sheet.merges.map(ref => `<mergeCell ref="${ref}"/>`).join("")}</mergeCells>`
    : "";

  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">
  <sheetPr>
    <pageSetUpPr fitToPage="1"/>
  </sheetPr>
  <dimension ref="A1:AC${sheet.lastRow}"/>
  <sheetViews>
    <sheetView workbookViewId="0"/>
  </sheetViews>
  <sheetFormatPr defaultRowHeight="15"/>
  <cols>
    <col min="1" max="1" width="2.2" customWidth="1"/>
    <col min="2" max="2" width="31" customWidth="1"/>
    <col min="3" max="27" width="3.55" customWidth="1"/>
    <col min="28" max="29" width="3.25" customWidth="1"/>
  </cols>
  <sheetData>${sheet.rows}</sheetData>
  ${mergeXml}
  <printOptions horizontalCentered="1"/>
  <pageMargins left="0.236" right="0.236" top="0.498" bottom="0.748" header="0.315" footer="0.315"/>
  <pageSetup paperSize="14" orientation="portrait" fitToWidth="1" fitToHeight="1"/>
  ${includeImage ? `<drawing r:id="rId${sheetIndex}"/>` : ""}
</worksheet>`;
}

