function buildZipEntryHeader(signature, nameBytes, size, crc, offset = 0) {
  const header = new Uint8Array(signature === 0x04034b50 ? 30 : 46);
  const view = new DataView(header.buffer);

  view.setUint32(0, signature, true);

  if (signature === 0x04034b50) {
    view.setUint16(4, 20, true);
    view.setUint16(6, 0, true);
    view.setUint16(8, 0, true);
    view.setUint16(10, 0, true);
    view.setUint16(12, 0, true);
    view.setUint32(14, crc, true);
    view.setUint32(18, size, true);
    view.setUint32(22, size, true);
    view.setUint16(26, nameBytes.length, true);
    view.setUint16(28, 0, true);
  } else {
    view.setUint16(4, 20, true);
    view.setUint16(6, 20, true);
    view.setUint16(8, 0, true);
    view.setUint16(10, 0, true);
    view.setUint16(12, 0, true);
    view.setUint16(14, 0, true);
    view.setUint32(16, crc, true);
    view.setUint32(20, size, true);
    view.setUint32(24, size, true);
    view.setUint16(28, nameBytes.length, true);
    view.setUint16(30, 0, true);
    view.setUint16(32, 0, true);
    view.setUint16(34, 0, true);
    view.setUint16(36, 0, true);
    view.setUint32(38, 0, true);
    view.setUint32(42, offset, true);
  }

  return header;
}

function getCrc32(bytes) {
  if (!getCrc32.table) {
    getCrc32.table = Array.from({ length: 256 }, (_, index) => {
      let value = index;

      for (let bit = 0; bit < 8; bit += 1) {
        value = value & 1 ? 0xedb88320 ^ (value >>> 1) : value >>> 1;
      }

      return value >>> 0;
    });
  }

  let crc = 0xffffffff;

  bytes.forEach(byte => {
    crc = getCrc32.table[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  });

  return (crc ^ 0xffffffff) >>> 0;
}

function concatBytes(parts) {
  const length = parts.reduce((total, part) => total + part.length, 0);
  const output = new Uint8Array(length);
  let offset = 0;

  parts.forEach(part => {
    output.set(part, offset);
    offset += part.length;
  });

  return output;
}

function buildZip(entries) {
  const encoder = new TextEncoder();
  const localParts = [];
  const centralParts = [];
  let offset = 0;

  entries.forEach(entry => {
    const nameBytes = encoder.encode(entry.name);
    const dataBytes = typeof entry.data === "string" ? encoder.encode(entry.data) : entry.data;
    const crc = getCrc32(dataBytes);
    const localHeader = buildZipEntryHeader(0x04034b50, nameBytes, dataBytes.length, crc);

    localParts.push(localHeader, nameBytes, dataBytes);

    const centralHeader = buildZipEntryHeader(0x02014b50, nameBytes, dataBytes.length, crc, offset);
    centralParts.push(centralHeader, nameBytes);

    offset += localHeader.length + nameBytes.length + dataBytes.length;
  });

  const centralDirectory = concatBytes(centralParts);
  const end = new Uint8Array(22);
  const view = new DataView(end.buffer);

  view.setUint32(0, 0x06054b50, true);
  view.setUint16(8, entries.length, true);
  view.setUint16(10, entries.length, true);
  view.setUint32(12, centralDirectory.length, true);
  view.setUint32(16, offset, true);

  return new Blob([...localParts, centralDirectory, end], {
    type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
  });
}

async function loadAttendanceHeaderImageBytes() {
  try {
    const response = await fetch(new URL("attendance-header.png", window.location.href));

    if (!response.ok) {
      throw new Error(`Header image request failed: ${response.status}`);
    }

    return new Uint8Array(await response.arrayBuffer());
  } catch (error) {
    console.warn("Attendance header image could not be embedded:", error);
  }

  try {
    const binary = atob(ATTENDANCE_HEADER_BASE64);
    const bytes = new Uint8Array(binary.length);

    for (let index = 0; index < binary.length; index += 1) {
      bytes[index] = binary.charCodeAt(index);
    }

    return bytes;
  } catch (error) {
    console.warn("Attendance header fallback could not be embedded:", error);
    return null;
  }
}

function buildOfficialAttendanceWorkbook({ sheetConfigs, imageBytes }) {
  const includeImage = Boolean(imageBytes);
  const sheetContentTypes = sheetConfigs
    .map((_, index) => `<Override PartName="/xl/worksheets/sheet${index + 1}.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>`)
    .join("");
  const drawingContentTypes = includeImage
    ? sheetConfigs.map((_, index) => `<Override PartName="/xl/drawings/drawing${index + 1}.xml" ContentType="application/vnd.openxmlformats-officedocument.drawing+xml"/>`).join("")
    : "";
  const imageContentType = includeImage
    ? `<Default Extension="png" ContentType="image/png"/>`
    : "";
  const workbookSheets = sheetConfigs
    .map((sheet, index) => `<sheet name="${escapeXML(sheet.name)}" sheetId="${index + 1}" r:id="rId${index + 1}"/>`)
    .join("");
  const workbookRels = sheetConfigs
    .map((_, index) => `<Relationship Id="rId${index + 1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet${index + 1}.xml"/>`)
    .join("");

  const entries = [
    {
      name: "[Content_Types].xml",
      data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml" ContentType="application/xml"/>
  ${imageContentType}
  <Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>
  <Override PartName="/xl/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.styles+xml"/>
  ${sheetContentTypes}
  ${drawingContentTypes}
</Types>`
    },
    {
      name: "_rels/.rels",
      data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>
</Relationships>`
    },
    {
      name: "xl/workbook.xml",
      data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">
  <sheets>${workbookSheets}</sheets>
</workbook>`
    },
    {
      name: "xl/_rels/workbook.xml.rels",
      data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  ${workbookRels}
  <Relationship Id="rId${sheetConfigs.length + 1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>
</Relationships>`
    },
    {
      name: "xl/styles.xml",
      data: buildOfficialAttendanceStylesXml()
    }
  ];

  sheetConfigs.forEach((sheet, index) => {
    entries.push({
      name: `xl/worksheets/sheet${index + 1}.xml`,
      data: buildOfficialAttendanceSheetXml({
        ...sheet,
        sheetIndex: index + 1,
        includeImage
      })
    });

    if (includeImage) {
      entries.push({
        name: `xl/worksheets/_rels/sheet${index + 1}.xml.rels`,
        data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId${index + 1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" Target="../drawings/drawing${index + 1}.xml"/>
</Relationships>`
      });
      entries.push({
        name: `xl/drawings/drawing${index + 1}.xml`,
        data: buildOfficialAttendanceDrawingXml()
      });
      entries.push({
        name: `xl/drawings/_rels/drawing${index + 1}.xml.rels`,
        data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/image1.png"/>
</Relationships>`
      });
    }
  });

  if (includeImage) {
    entries.push({
      name: "xl/media/image1.png",
      data: imageBytes
    });
  }

  return buildZip(entries);
}

async function downloadMonthlyAttendanceSpreadsheet() {
  ensureAttendanceDefaults();

  const monthValue = attendanceMonth ? attendanceMonth.value : getCurrentMonthISO();
  const monthLabel = getMonthFileLabel(monthValue);
  const dateChunks = chunkItems(getMonthlyAttendanceDates(monthValue), 25);
  const rows = getMonthlyAttendanceRows(monthValue);
  const sectionLabel = students[0] && students[0].section
    ? students[0].section
    : "Grade & Section";
  const imageBytes = await loadAttendanceHeaderImageBytes();
  const sheetConfigs = dateChunks.map((dateValues, index) => ({
    name: dateChunks.length > 1 ? `${monthLabel.slice(0, 25)} ${index + 1}` : monthLabel.slice(0, 31),
    rows,
    dateValues,
    sectionLabel,
    monthLabel: dateChunks.length > 1 ? `${monthLabel} (${index + 1}/${dateChunks.length})` : monthLabel
  }));
  const workbookBlob = buildOfficialAttendanceWorkbook({ sheetConfigs, imageBytes });
  const url = URL.createObjectURL(workbookBlob);
  const link = document.createElement("a");

  link.href = url;
  link.download = `DAILY-ATTENDANCE-${monthLabel.replace(/[^a-z0-9]+/gi, "-").toUpperCase()}.xlsx`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);

  showToast("Monthly attendance spreadsheet downloaded.");
}

function buildOfficialAttendanceGroup(group, dateValues, minimumRows, showLabel = true) {
  const slotCount = Math.max(minimumRows, group.rows.length);
  const slots = Array.from({ length: slotCount }, (_, index) => group.rows[index] || null);

  return `
    ${showLabel ? `
      <tr class="group-row">
        <td colspan="2">${group.label}</td>
      </tr>
    ` : ""}
    ${slots.map((row, index) => `
      <tr${(index + 1) % 5 === 0 ? ` class="block-end"` : ""}>
        <td class="num">${index + 1}</td>
        <td class="student-name">${row ? escapeHTML(row.student.name).toUpperCase() : ""}</td>
        ${dateValues.map((dateValue, dateIndex) => `
          <td class="mark${(dateIndex + 1) % 5 === 0 ? " week-end" : ""}">${row ? getAttendancePrintMark(row.student.id, dateValue) : ""}</td>
        `).join("")}
        <td class="total">${row ? getMonthlyAttendanceStatusTotal(row.student.id, dateValues, "Tardy") || "" : ""}</td>
        <td class="total">${row ? getMonthlyAttendanceStatusTotal(row.student.id, dateValues, "Absent") || "" : ""}</td>
      </tr>
    `).join("")}
  `;
}

